            if dist_to_truck < total_time:
                total_time += total_time - dist_to_truck
        if total_time < min_time:
            min_time = total_time
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    best_node = None
    min_combined_metric = float('inf')

    for i, customer in enumerate(unvisited_customers):
        total_distance = np.linalg.norm(cur_truck_pos - customer)
        for truck_pos in all_truck_pos:
            dist_to_truck = np.linalg.norm(truck_pos - customer)
            total_distance += dist_to_truck
        if total_distance < min_combined_metric:
            min_combined_metric = total_distance
            best_node = i

    return best_node
